using UnityEngine;
using UnityEngine.Events;

/// <summary>
/// Alavanca genérica on/off (Etapa 6.1). Escreve o seu estado numa variável
/// global (GameVariables) — usada para abrir portas, desligar lasers e
/// desactivar inimigos (Condition_GlobalBoolVariable — Etapa 5.4).
///
/// Exemplo (GDD): alavanca com variableName = "TorretaSala01Desativada" —
/// ao ligar, todas as torretas com essa condição de desactivação desligam.
///
/// Activação: <see cref="Toggle"/>/<see cref="SetOn"/> (chamável por input de
/// interacção, NpcAction, etc) e/ou toque do player ("toggleOnPlayerTouch").
///
/// Persistência: se <see cref="persistState"/> estiver activo, ao reentrar na
/// cena (após morte/saída de área) a alavanca restaura o estado a partir de
/// <see cref="variableName"/> em vez de começar pelo valor Inspector — o puzzle
/// "fica resolvido". Se desactivo (padrão), a alavanca volta ao estado Inspector
/// ao carregar → puzzle "de tentativa" que reinicia.
/// </summary>
public class Lever : MonoBehaviour
{
    [Header("Estado")]
    public bool isOn = false;

    [Header("Variável Global (GameVariables)")]
    [Tooltip("Nome da variável global escrita com o estado da alavanca. Vazio = não escreve.")]
    public string variableName = "";

    [Tooltip("Se activo, escreve a variável como INT (1/0) em vez de BOOL — para condições Condition_GlobalIntVariable.")]
    public bool writeAsInt = false;

    [Header("Persistência após Morte / Saída de Área")]
    [Tooltip("GDD: 'Puzzles concluídos permanecem resolvidos quando configurados como persistentes; puzzles de tentativa ou movimento podem reiniciar.'\n\nLigado → ao reentrar na cena, restaura 'isOn' a partir de 'variableName' (GameVariables) — o puzzle mantém-se resolvido.\nDesligado (padrão) → ao carregar, escreve o valor padrão do Inspector → puzzle reinicia.")]
    public bool persistState = false;

    [Header("Activação")]
    [Tooltip("O toque do player (trigger) alterna a alavanca.")]
    public bool toggleOnPlayerTouch = false;

    [Tooltip("Só pode ser alternada uma vez (fica presa no novo estado).")]
    public bool oneShot = false;

    [Header("Visual (opcional)")]
    public SpriteRenderer spriteRenderer;
    public Sprite spriteOn;
    public Sprite spriteOff;

    [Header("Eventos")]
    public UnityEvent<bool> onToggled;

    private bool _used;

    private void Start()
    {
        if (persistState && !string.IsNullOrEmpty(variableName) && GameVariables.Instance != null)
        {
            // Restaura o estado a partir da variável global persistida — não
            // sobrescreve com o padrão Inspector (evita apagar o estado guardado
            // quando a cena recarrega após morte ou saída de área).
            bool saved = writeAsInt
                ? GameVariables.Instance.GetInt(variableName) != 0
                : GameVariables.Instance.GetBool(variableName);
            isOn = saved;
            ApplyVisual();
        }
        else
        {
            // Comportamento padrão (puzzle "de tentativa"): escreve o padrão
            // Inspector na variável global, garantindo que a cena começa no
            // estado correcto.
            Apply();
        }
    }

    /// <summary>Alterna on/off (respeita "oneShot").</summary>
    public void Toggle() => SetOn(!isOn);

    /// <summary>Define o estado e aplica (variável global + visual + evento).</summary>
    public void SetOn(bool value)
    {
        if (oneShot && _used) return;
        if (isOn == value) return;

        isOn = value;
        _used = true;
        Apply();
        onToggled?.Invoke(isOn);
    }

    private void Apply()
    {
        if (!string.IsNullOrEmpty(variableName) && GameVariables.Instance != null)
        {
            if (writeAsInt) GameVariables.Instance.SetInt(variableName, isOn ? 1 : 0);
            else GameVariables.Instance.SetBool(variableName, isOn);
        }

        ApplyVisual();
    }

    /// <summary>Actualiza apenas o visual (sprite) sem alterar a variável global — usado ao restaurar estado persistido.</summary>
    private void ApplyVisual()
    {
        if (spriteRenderer != null)
        {
            var sprite = isOn ? spriteOn : spriteOff;
            if (sprite != null) spriteRenderer.sprite = sprite;
        }
    }

    private void OnTriggerEnter2D(Collider2D other)
    {
        if (toggleOnPlayerTouch && other.CompareTag("Player"))
            Toggle();
    }
}
